@code {
    [Parameter] public int? Id { get; set; }

    private PatientModel model = new();
    private List<Owner> existingOwners = new();

    private class PatientModel
    {
        public string PetName { get; set; } = string.Empty;
        public string Species { get; set; } = string.Empty;
        public string Breed { get; set; } = string.Empty;
        public DateTime DateOfBirth { get; set; } = DateTime.Today;
        public decimal Weight { get; set; }
        public int? OwnerId { get; set; }
        public string OwnerFirstName { get; set; } = string.Empty;
        public string OwnerLastName { get; set; } = string.Empty;
        public string OwnerPhone { get; set; } = string.Empty;
        public string OwnerEmail { get; set; } = string.Empty;
        public string OwnerAddress { get; set; } = string.Empty;
    }

    protected override async Task OnInitializedAsync()
    {
        existingOwners = await Db.Owners.OrderBy(o => o.LastName).ToListAsync();

        if (Id.HasValue)
        {
            var pet = await Db.Pets.Include(p => p.Owner).FirstOrDefaultAsync(p => p.Id == Id.Value);
            if (pet is not null)
            {
                model.PetName = pet.Name;
                model.Species = pet.Species;
                model.Breed = pet.Breed;
                model.DateOfBirth = pet.DateOfBirth;
                model.Weight = pet.Weight;
                model.OwnerId = pet.OwnerId;
                model.OwnerFirstName = pet.Owner.FirstName;
                model.OwnerLastName = pet.Owner.LastName;
                model.OwnerPhone = pet.Owner.Phone;
                model.OwnerEmail = pet.Owner.Email;
                model.OwnerAddress = pet.Owner.Address;
            }
        }
    }

    private void OnOwnerSelected(ChangeEventArgs e)
    {
        if (int.TryParse(e.Value?.ToString(), out var ownerId))
        {
            var owner = existingOwners.FirstOrDefault(o => o.Id == ownerId);
            if (owner is not null)
            {
                model.OwnerId = owner.Id;
                model.OwnerFirstName = owner.FirstName;
                model.OwnerLastName = owner.LastName;
                model.OwnerPhone = owner.Phone;
                model.OwnerEmail = owner.Email;
                model.OwnerAddress = owner.Address;
            }
        }
        else
        {
            model.OwnerId = null;
            model.OwnerFirstName = string.Empty;
            model.OwnerLastName = string.Empty;
            model.OwnerPhone = string.Empty;
            model.OwnerEmail = string.Empty;
            model.OwnerAddress = string.Empty;
        }
    }

    private async Task Save()
    {
        Owner owner;
        if (model.OwnerId.HasValue)
        {
            owner = await Db.Owners.FindAsync(model.OwnerId.Value) ?? new Owner();
        }
        else
        {
            owner = new Owner();
            Db.Owners.Add(owner);
        }
        owner.FirstName = model.OwnerFirstName;
        owner.LastName = model.OwnerLastName;
        owner.Phone = model.OwnerPhone;
        owner.Email = model.OwnerEmail;
        owner.Address = model.OwnerAddress;

        Pet pet;
        if (Id.HasValue)
        {
            pet = await Db.Pets.FindAsync(Id.Value) ?? new Pet();
        }
        else
        {
            pet = new Pet();
            Db.Pets.Add(pet);
        }
        pet.Name = model.PetName;
        pet.Species = model.Species;
        pet.Breed = model.Breed;
        pet.DateOfBirth = model.DateOfBirth;
        pet.Weight = model.Weight;
        pet.Owner = owner;

        await Db.SaveChangesAsync();
        Nav.NavigateTo("/patients");
    }
}
