        <table class="table">
            <thead>
                <tr><th>Time</th><th>Status</th><th>Pet</th><th>Reason</th><th>Actions</th></tr>
            </thead>
            <tbody>
                @foreach (var slot in timeSlots)
                {
                    var appointment = appointments.FirstOrDefault(a => 
                        a.DateTime.LocalDateTime.Hour == slot.Hour && 
                        a.DateTime.LocalDateTime.Minute == slot.Minute);
                    <tr class="@(appointment is not null ? "table-info" : "")">
                        <td>@slot.ToString("h:mm tt")</td>
                        @if (appointment is not null)
                        {
                            <td><span class="badge bg-@GetStatusColor(appointment.Status)">@appointment.Status</span></td>
                            <td>@appointment.Pet.Name</td>
                            <td>@appointment.Reason</td>
                            <td>
                                @if (appointment.Status == AppointmentStatus.Scheduled)
                                {
                                    <a href="/appointments/@appointment.Id/edit" class="btn btn-sm btn-outline-primary">Reschedule</a>
                                    <button class="btn btn-sm btn-outline-danger ms-1" @onclick="() => CancelAppointment(appointment)">Cancel</button>
                                    <button class="btn btn-sm btn-outline-success ms-1" @onclick="() => CompleteAppointment(appointment)">Complete</button>
                                }
                            </td>
                        }
                        else
                        {
                            <td><span class="badge bg-light text-dark">Available</span></td>
                            <td colspan="3"></td>
                        }
                    </tr>
                }
            </tbody>
        </table>
    </div>
</div>

@code {
    private DateTime selectedDate = DateTime.Today;
    private List<Appointment> appointments = new();
    private List<DateTime> timeSlots = new();

    protected override async Task OnInitializedAsync()
    {
        GenerateTimeSlots();
        await LoadAppointments();
    }

    private void GenerateTimeSlots()
    {
        timeSlots.Clear();
        for (int hour = 9; hour < 17; hour++)
        {
            timeSlots.Add(new DateTime(selectedDate.Year, selectedDate.Month, selectedDate.Day, hour, 0, 0));
            timeSlots.Add(new DateTime(selectedDate.Year, selectedDate.Month, selectedDate.Day, hour, 30, 0));
        }
    }

    private async Task LoadAppointments()
    {
        GenerateTimeSlots();
        var start = new DateTimeOffset(selectedDate, TimeSpan.Zero);
        var end = start.AddDays(1);
        appointments = await Db.Appointments
            .Include(a => a.Pet)
            .Where(a => a.DateTime >= start && a.DateTime < end && a.Status != AppointmentStatus.Cancelled)
            .OrderBy(a => a.DateTime)
            .ToListAsync();
    }

    private async Task CancelAppointment(Appointment apt)
    {
        apt.Status = AppointmentStatus.Cancelled;
        await Db.SaveChangesAsync();
        await LoadAppointments();
    }

    private async Task CompleteAppointment(Appointment apt)
    {
        apt.Status = AppointmentStatus.Completed;
        await Db.SaveChangesAsync();
        await LoadAppointments();
    }

    private string GetStatusColor(AppointmentStatus status) => status switch
    {
        AppointmentStatus.Scheduled => "primary",
        AppointmentStatus.Completed => "success",
        AppointmentStatus.Cancelled => "danger",
        _ => "secondary"
    };
}

