    {
        filter = newFilter;
        await LoadInvoices();
    }

    private async Task LoadInvoices()
    {
        var query = Db.Invoices.Include(i => i.Pet).AsQueryable();
        if (filter != "All")
        {
            var status = Enum.Parse<InvoiceStatus>(filter);
            query = query.Where(i => i.Status == status);
        }
        invoices = await query.OrderByDescending(i => i.CreatedDate).ToListAsync();
