                    <td>@((model.LineItems[index].Quantity * model.LineItems[index].UnitPrice).ToString("C"))</td>
                    <td><button type="button" class="btn btn-sm btn-danger" @onclick="() => RemoveLineItem(index)">X</button></td>
                </tr>
            }
        </tbody>
    </table>
    <button type="button" class="btn btn-outline-secondary mb-3" @onclick="AddLineItem">+ Add Line Item</button>

    <div class="mb-3">
        <strong>Total: @CalculateTotal().ToString("C")</strong>
    </div>

    <button type="submit" class="btn btn-primary">@(Id.HasValue ? "Update" : "Create") Invoice</button>
    <a href="/billing" class="btn btn-secondary ms-2">Cancel</a>
</EditForm>

@code {
    [Parameter] public int? Id { get; set; }

    private InvoiceModel model = new();
    private List<Pet> pets = new();
    private List<Appointment> appointments = new();

    private class LineItemModel
    {
        public int? ExistingId { get; set; }
        public string Description { get; set; } = string.Empty;
        public int Quantity { get; set; } = 1;
        public decimal UnitPrice { get; set; }
    }

    private class InvoiceModel
    {
        public int PetId { get; set; }
        public string AppointmentId { get; set; } = string.Empty;
        public DateTime DueDate { get; set; } = DateTime.Today.AddDays(30);
        public List<LineItemModel> LineItems { get; set; } = new() { new LineItemModel() };
    }

    protected override async Task OnInitializedAsync()
    {
        pets = await Db.Pets.OrderBy(p => p.Name).ToListAsync();
        appointments = await Db.Appointments.Where(a => a.Status == AppointmentStatus.Completed).OrderByDescending(a => a.DateTime).ToListAsync();

        if (Id.HasValue)
        {
            var invoice = await Db.Invoices.Include(i => i.LineItems).FirstOrDefaultAsync(i => i.Id == Id.Value);
            if (invoice is not null)
            {
                model.PetId = invoice.PetId;
                model.AppointmentId = invoice.AppointmentId?.ToString() ?? string.Empty;
                model.DueDate = invoice.DueDate;
                model.LineItems = invoice.LineItems.Select(li => new LineItemModel
                {
                    ExistingId = li.Id,
                    Description = li.Description,
                    Quantity = li.Quantity,
                    UnitPrice = li.UnitPrice
                }).ToList();
                if (!model.LineItems.Any()) model.LineItems.Add(new LineItemModel());
            }
        }
    }

    private void AddLineItem() => model.LineItems.Add(new LineItemModel());
    private void RemoveLineItem(int index) { if (model.LineItems.Count > 1) model.LineItems.RemoveAt(index); }
    private decimal CalculateTotal() => model.LineItems.Sum(li => li.Quantity * li.UnitPrice);

    private async Task Save()
    {
        if (model.PetId == 0) return;

        Invoice invoice;
        if (Id.HasValue)
        {
            invoice = await Db.Invoices.Include(i => i.LineItems).FirstOrDefaultAsync(i => i.Id == Id.Value) ?? new Invoice();
            invoice.LineItems.Clear();
        }
        else
        {
            invoice = new Invoice { CreatedDate = DateTime.Today };
            Db.Invoices.Add(invoice);
        }

        invoice.PetId = model.PetId;
        invoice.AppointmentId = int.TryParse(model.AppointmentId, out var aptId) ? aptId : null;
        invoice.DueDate = model.DueDate;
        invoice.TotalAmount = CalculateTotal();

        foreach (var li in model.LineItems)
        {
            invoice.LineItems.Add(new InvoiceLineItem
            {
                Description = li.Description,
                Quantity = li.Quantity,
                UnitPrice = li.UnitPrice
            });
        }

        await Db.SaveChangesAsync();
        Nav.NavigateTo("/billing");
    }
}

