@code {
    [Parameter] public int Id { get; set; }

    private Invoice? invoice;
    private Payment newPayment = new() { Date = DateTime.Today };

    protected override async Task OnInitializedAsync()
    {
        await LoadInvoice();
    }

    private async Task LoadInvoice()
    {
        invoice = await Db.Invoices
            .Include(i => i.Pet)
            .Include(i => i.LineItems)
            .Include(i => i.Payments)
            .FirstOrDefaultAsync(i => i.Id == Id);
    }

    private async Task SavePayment()
    {
        newPayment.InvoiceId = Id;
        Db.Payments.Add(newPayment);

        // Update invoice status if fully paid
        if (invoice is not null)
        {
            var totalPaid = invoice.Payments.Sum(p => p.Amount) + newPayment.Amount;
            if (totalPaid >= invoice.TotalAmount)
            {
                invoice.Status = InvoiceStatus.Paid;
            }
        }

        await Db.SaveChangesAsync();
        newPayment = new Payment { Date = DateTime.Today };
        await LoadInvoice();
    }

    private string GetStatusColor(InvoiceStatus status) => status switch
    {
        InvoiceStatus.Pending => "warning",
        InvoiceStatus.Paid => "success",
        InvoiceStatus.Overdue => "danger",
        InvoiceStatus.Cancelled => "secondary",
        _ => "secondary"
    };
