+        <label class="form-label">Notes</label>
+        <InputTextArea class="form-control" @bind-Value="model.Notes" />
+    </div>
+
+    <button type="submit" class="btn btn-primary">@(Id.HasValue ? "Update" : "Create")</button>
+    <a href="/appointments" class="btn btn-secondary ms-2">Cancel</a>
+</EditForm>
+
+@if (availableSlots.Any())
+{
+    <div class="mt-3">
+        <h5>Available Slots for @model.Date.ToString("MMMM d, yyyy")</h5>
+        <div class="d-flex flex-wrap gap-1">
+            @foreach (var slot in availableSlots)
+            {
+                <span class="badge bg-success">@slot.ToString("h:mm tt")</span>
+            }
+        </div>
+    </div>
+}
+
+@code {
+    [Parameter] public int? Id { get; set; }
+
+    private AppointmentModel model = new();
+    private List<Pet> pets = new();
+    private List<DateTime> availableSlots = new();
+
+    private class AppointmentModel
+    {
+        public int PetId { get; set; }
+        public DateTime Date { get; set; } = DateTime.Today;
+        public string TimeSlot { get; set; } = string.Empty;
+        public int DurationMinutes { get; set; } = 30;
+        public string Reason { get; set; } = string.Empty;
+        public string Notes { get; set; } = string.Empty;
+    }
+
+    protected override async Task OnInitializedAsync()
+    {
+        pets = await Db.Pets.Include(p => p.Owner).OrderBy(p => p.Name).ToListAsync();
+
+        if (Id.HasValue)
+        {
+            var apt = await Db.Appointments.FindAsync(Id.Value);
+            if (apt is not null)
+            {
+                model.PetId = apt.PetId;
+                model.Date = apt.DateTime.LocalDateTime.Date;
+                model.TimeSlot = apt.DateTime.LocalDateTime.ToString("HH:mm");
+                model.DurationMinutes = apt.DurationMinutes;
+                model.Reason = apt.Reason;
+                model.Notes = apt.Notes;
+            }
+        }
+
+        await LoadAvailableSlots();
+    }
+
+    private async Task LoadAvailableSlots()
+    {
+        var start = new DateTimeOffset(model.Date, TimeSpan.Zero);
+        var end = start.AddDays(1);
+        var booked = await Db.Appointments
+            .Where(a => a.DateTime >= start && a.DateTime < end && a.Status != AppointmentStatus.Cancelled)
+            .Select(a => a.DateTime.LocalDateTime)
+            .ToListAsync();
+
+        availableSlots.Clear();
+        for (int hour = 9; hour < 17; hour++)
+        {
+            var slot0 = new DateTime(model.Date.Year, model.Date.Month, model.Date.Day, hour, 0, 0);
+            var slot30 = new DateTime(model.Date.Year, model.Date.Month, model.Date.Day, hour, 30, 0);
+            if (!booked.Any(b => b.Hour == slot0.Hour && b.Minute == slot0.Minute))
+                availableSlots.Add(slot0);
+            if (!booked.Any(b => b.Hour == slot30.Hour && b.Minute == slot30.Minute))
+                availableSlots.Add(slot30);
+        }
+    }
+
+    private async Task Save()
+    {
+        if (model.PetId == 0 || string.IsNullOrEmpty(model.TimeSlot)) return;
+
+        var timeParts = model.TimeSlot.Split(':');
+        var dateTime = new DateTimeOffset(model.Date.Year, model.Date.Month, model.Date.Day,
+            int.Parse(timeParts[0]), int.Parse(timeParts[1]), 0, TimeSpan.Zero);
+
+        Appointment apt;
+        if (Id.HasValue)
+        {
+            apt = await Db.Appointments.FindAsync(Id.Value) ?? new Appointment();
+        }
+        else
+        {
+            apt = new Appointment();
+            Db.Appointments.Add(apt);
+        }
+
+        apt.PetId = model.PetId;
+        apt.DateTime = dateTime;
+        apt.DurationMinutes = model.DurationMinutes;
+        apt.Reason = model.Reason;
+        apt.Notes = model.Notes;
+
+        await Db.SaveChangesAsync();
+        Nav.NavigateTo("/appointments");
+    }
+}
+

